PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX dcterms: <http://purl.org/dc/terms/>
PREFIX gb: <https://lambdasistemi.github.io/graph-browser/vocab/terms#>
PREFIX gbk: <https://lambdasistemi.github.io/graph-browser/vocab/kinds#>
SELECT DISTINCT ?node WHERE {
  { ?node a gbk:ffi }
  UNION {
    ?ffi a gbk:ffi ; ?p ?node .
    ?node gb:nodeId ?nodeId .
    FILTER(?p != rdf:type && ?p != gb:group && ?p != dcterms:isPartOf)
  }
  UNION {
    ?node ?p ?ffi .
    ?ffi a gbk:ffi .
    ?node gb:nodeId ?nodeId .
    FILTER(?p != rdf:type && ?p != gb:group && ?p != dcterms:isPartOf)
  }
}

