PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX dcterms: <http://purl.org/dc/terms/>
PREFIX gb: <https://lambdasistemi.github.io/graph-browser/vocab/terms#>
SELECT ?node WHERE {
  { SELECT ?node (COUNT(*) AS ?c) WHERE {
    { ?node ?p ?other . ?other gb:nodeId ?otherId }
    UNION { ?other ?p ?node . ?other gb:nodeId ?otherId }
    FILTER(?p != rdf:type && ?p != gb:group && ?p != dcterms:isPartOf)
  } GROUP BY ?node HAVING (COUNT(*) = 1) }
}

PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX dcterms: <http://purl.org/dc/terms/>
PREFIX gb: <https://lambdasistemi.github.io/graph-browser/vocab/terms#>
