PREFIX owl: <http://www.w3.org/2002/07/owl#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT DISTINCT ?node WHERE {
  { ?class a owl:Class }
  UNION { ?class a rdfs:Class }
  BIND(CONCAT("owl-", LCASE(REPLACE(REPLACE(STR(?class), "^.*(#|/)", ""), "[^A-Za-z0-9]+", "-"))) AS ?node)
}

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT DISTINCT ?node WHERE {
  {
    ?child rdfs:subClassOf ?parent .
    BIND(?child AS ?class)
  }
  UNION {
    ?child rdfs:subClassOf ?parent .
    BIND(?parent AS ?class)
  }
  FILTER(isIRI(?class))
  BIND(CONCAT("owl-", LCASE(REPLACE(REPLACE(STR(?class), "^.*(#|/)", ""), "[^A-Za-z0-9]+", "-"))) AS ?node)
}

PREFIX owl: <http://www.w3.org/2002/07/owl#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT DISTINCT ?node WHERE {
  {
    ?property a owl:ObjectProperty ; rdfs:domain ?class .
    FILTER(isIRI(?class))
    BIND(CONCAT("owl-", LCASE(REPLACE(REPLACE(STR(?class), "^.*(#|/)", ""), "[^A-Za-z0-9]+", "-"))) AS ?node)
  }
  UNION
  {
    ?property a owl:ObjectProperty ; rdfs:range ?class .
    FILTER(isIRI(?class))
    BIND(CONCAT("owl-", LCASE(REPLACE(REPLACE(STR(?class), "^.*(#|/)", ""), "[^A-Za-z0-9]+", "-"))) AS ?node)
  }
}

PREFIX owl: <http://www.w3.org/2002/07/owl#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT DISTINCT ?node WHERE {
  {
    ?class owl:equivalentClass ?other .
    FILTER(isIRI(?class))
  }
  UNION
  {
    ?other owl:equivalentClass ?class .
    FILTER(isIRI(?class))
  }
  UNION
  {
    ?leftProp owl:equivalentProperty ?rightProp .
    ?leftProp rdfs:domain ?class .
    FILTER(isIRI(?class))
  }
  UNION
  {
    ?leftProp owl:equivalentProperty ?rightProp .
    ?rightProp rdfs:domain ?class .
    FILTER(isIRI(?class))
  }
  UNION
  {
    ?leftProp owl:equivalentProperty ?rightProp .
    ?leftProp rdfs:range ?class .
    FILTER(isIRI(?class))
  }
  UNION
  {
    ?leftProp owl:equivalentProperty ?rightProp .
    ?rightProp rdfs:range ?class .
    FILTER(isIRI(?class))
  }
  BIND(CONCAT("owl-", LCASE(REPLACE(REPLACE(STR(?class), "^.*(#|/)", ""), "[^A-Za-z0-9]+", "-"))) AS ?node)
}
